                        let retrieval_policy_gate =
                            build_retrieval_policy_decision_gate(&bundle_check);
                        let approval_delegation_gate = build_approval_delegation_evidence_gate(
                            &store,
                            &role_selection,
                            &run_graph_bootstrap,
